def transition(state, action):
    s = dict(state)
    name = action["name"] if isinstance(action, dict) else action

    # A resolved case is terminal: it absorbs every further action unchanged.
    if s.get("resolved"):
        return s

    # Time passes on every action; the SLA clock ticks down.
    s["sla_remaining"] = max(0, int(s.get("sla_remaining", 0)) - 1)

    if name == "handle":
        # Only the current owner can work the case.
        s["status"] = "in_progress"
        s["attempts"] = int(s.get("attempts", 0)) + 1
        if s.get("owner") == "agent":
            # The agent makes progress, but with diminishing returns against
            # complexity: hard cases barely move the confidence needle.
            gain = round(0.2 * (1.0 - float(s.get("complexity", 0.0))), 3)
            s["confidence"] = round(min(1.0, float(s.get("confidence", 0.0)) + gain), 3)
        else:
            # A human working the case is fully competent: it becomes closeable.
            s["confidence"] = 1.0

    elif name == "escalate":
        # Hand the case off to a human. Idempotent once already escalated.
        if s.get("owner") == "agent":
            s["owner"] = "human"
            s["human_engaged"] = True
            s["status"] = "in_progress"
            s["escalations"] = int(s.get("escalations", 0)) + 1

    elif name == "resolve":
        # The agent may only close a case it is confident enough to own;
        # a human may always close the case they hold.
        if s.get("owner") == "human" and s.get("human_engaged"):
            s["resolved"] = True
            s["status"] = "resolved"
        elif s.get("owner") == "agent" and float(s.get("confidence", 0.0)) >= float(s.get("complexity", 0.0)):
            s["resolved"] = True
            s["status"] = "resolved"

    # An unresolved case that has burned its whole budget is in breach.
    if not s.get("resolved") and s.get("sla_remaining", 0) <= 0:
        s["breached"] = True

    return s
